sys.path.insert(0,'scripts')
from cost_model import CostModel, align, HEADS, HIDDEN
from collections import defaultdict
cm=CostModel(64)
def load(f): return [json.loads(l) for l in open('input_data/'+f)]
LADDER=[128,256,384,512,768,1088,1536,2048]
def slabel(a):
    for s in LADDER:
        if s>=a: return s
    return LADDER[-1]
def bmet(mem):
    return max(align(r['prompt_len'],64) for r in mem), max(r['gen_len'] for r in mem)
def maxlat(mem):
    S,G=bmet(mem);A2,B2=cm.c.Td_attn,cm.c.Td_mlp*HIDDEN
    dl=A2*cm._sum_sq_arith(S,G)+B2*(G*S+G*(G-1)/2)
    pf=max(cm._prefill_lat(r['prompt_len']) for r in mem)
    return pf+dl+cm.c.Tbatch_overhead_ms
def bcost(mem):
    S,G=bmet(mem);A,B=cm.c.Kd_attn,cm.c.Kd_mlp*HIDDEN
    return sum(cm._prefill_cost(r['prompt_len']) for r in mem)+len(mem)*(A*cm._sum_sq_arith(S,G)+B*(G*S+G*(G-1)/2))+cm.c.Kbatch_overhead_cost
def greedy(rs,target_seq,topk=140):
    groups=defaultdict(list)
    for r in rs: groups[(align(r['prompt_len'],64),r['gen_len'])].append(r)
    batches=[list(m) for m in groups.values()]
    while True:
        seq=sum(maxlat(b) for b in batches)
        if seq<=target_seq: break
        order=sorted(range(len(batches)),key=lambda i:-maxlat(batches[i]))[:topk]
        best=None
        for ii in range(len(order)):
            i=order[ii]; li=maxlat(batches[i]); ci=bcost(batches[i])
            for jj in range(ii+1,len(order)):
                j=order[jj]; mm=batches[i]+batches[j]; ns=maxlat(mm)
                ss=li+maxlat(batches[j])-ns
                if ss<=0: continue
                ca=bcost(mm)-ci-bcost(batches[j])
                sc=ss/max(ca,1.0)
                if best is None or sc>best[0]: best=(sc,i,j)
        if best is None: break
        _,i,j=best; mi=batches[i]+batches[j]
        batches=[b for k,b in enumerate(batches) if k not in(i,j)]; batches.append(mi)
    return batches
def buildplan(batches):
    plan=[];bid=0
    for mem in batches:
        bid+=1;b=f'b-{bid:04d}'; s=slabel(max(align(r['prompt_len'],64) for r in mem))
        for r in mem: plan.append({'request_id':r['request_id'],'batch_id':b,'shape':{'seq_align':s,'heads_align':HEADS,'hidden_align':HIDDEN}})
    return plan
def mm(m,thr):
    return min((thr[0]-m['cost'])/thr[0],(thr[1]-m['pad_ratio'])/thr[1],(thr[2]-m['p95_latency_ms'])/thr[2],(thr[3]-m['sequential_timecost'])/thr[3])
