        rs=load(f);reqs={r['request_id']:r for r in rs}
        best=None
        for ts in [t*thr[3] for t in (0.90,0.92,0.94,0.95,0.96,0.97,0.98)]:
            batches=greedy(rs,ts); plan=buildplan(batches); m=cm.plan_metrics(reqs,plan)
